# Protobuf definitions (would normally be in .proto files and compiled)
# For this implementation, we'll use manual message classes

class AuthRequest:
    def __init__(self, username='', password=''):
        self.username = username
        self.password = password

class AuthResponse:
    def __init__(self, success=False, token='', message=''):
        self.success = success
        self.token = token
        self.message = message

class DataRequest:
    def __init__(self, token='', data_id=''):
        self.token = token
        self.data_id = data_id

class DataResponse:
    def __init__(self, success=False, data='', message=''):
        self.success = success
        self.data = data
        self.message = message

class UserListRequest:
    def __init__(self, token=''):
        self.token = token

class UserListResponse:
    def __init__(self, success=False, users=None, message=''):
        self.success = success
        self.users = users or []
        self.message = message

# Server Implementation
class MicroserviceServicer:
    def __init__(self):
        self.users = {
            'admin': hashlib.sha256('admin123'.encode()).hexdigest(),
            'user1': hashlib.sha256('password1'.encode()).hexdigest(),
            'user2': hashlib.sha256('password2'.encode()).hexdigest()
        }
        self.tokens = {}
        self.data_store = {
            'data1': {'id': 'data1', 'content': 'Sample data 1', 'timestamp': '2024-01-01'},
            'data2': {'id': 'data2', 'content': 'Sample data 2', 'timestamp': '2024-01-02'},
            'data3': {'id': 'data3', 'content': 'Sample data 3', 'timestamp': '2024-01-03'}
        }

    def Authenticate(self, request, context):
        username = request.username
        password = request.password
        password_hash = hashlib.sha256(password.encode()).hexdigest()
        
        if username in self.users and self.users[username] == password_hash:
            token = hashlib.sha256(f"{username}{time.time()}".encode()).hexdigest()
            self.tokens[token] = {'username': username, 'created': time.time()}
            return AuthResponse(success=True, token=token, message='Authentication successful')
        else:
            return AuthResponse(success=False, token='', message='Invalid credentials')

    def GetData(self, request, context):
        token = request.token
        data_id = request.data_id
        
        if token not in self.tokens:
            return DataResponse(success=False, data='', message='Invalid or expired token')
        
        if data_id in self.data_store:
            data_json = json.dumps(self.data_store[data_id])
            return DataResponse(success=True, data=data_json, message='Data retrieved successfully')
        else:
            return DataResponse(success=False, data='', message='Data not found')

    def ListUsers(self, request, context):
        token = request.token
        
        if token not in self.tokens:
            return UserListResponse(success=False, users=[], message='Invalid or expired token')
        
        user_list = list(self.users.keys())
        return UserListResponse(success=True, users=user_list, message='Users retrieved successfully')

# Manual RPC handler
class MicroserviceServer:
    def __init__(self):
        self.servicer = MicroserviceServicer()

    def handle_request(self, method, request_data):
        if method == 'Authenticate':
            request = AuthRequest(**request_data)
            return self.servicer.Authenticate(request, None)
        elif method == 'GetData':
            request = DataRequest(**request_data)
            return self.servicer.GetData(request, None)
        elif method == 'ListUsers':
            request = UserListRequest(**request_data)
            return self.servicer.ListUsers(request, None)
        else:
            return None

def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    servicer = MicroserviceServicer()
    
    # Register the servicer
    server.servicer = servicer
    
    # Bind to port
    server.add_insecure_port('[::]:50051')
    
    print("Server starting on port 50051...")
    server.start()
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        print("\nShutting down server...")
        server.stop(0)

